 28	public class TrustStoreValidator implements TrustValidator {
 29	
 30	  private static final Logger log = LoggerFactory.getLogger(TrustStoreValidator.class);
 31	
 32	  private static final ASN1ObjectIdentifier OID_EPA_VAU =
 33	      new ASN1ObjectIdentifier("1.2.276.0.76.4.209");
 34	
 35	  // for test/mock purposed
 36	  static Clock clock = Clock.systemUTC();
 37	
 38	  // A_24624-01/1
 39	  private static final Duration ocspResponseAge = Duration.ofHours(24);
 40	
 41	  private final KeyStore trustStore;
 42	
 43	  public TrustStoreValidator(KeyStore trustStore) {
 44	    this.trustStore = trustStore;
 45	  }
 46	
 47	  @Override
 48	  public void validate(
 49	      X509Certificate vauInstanceCertificate,
 50	      X509Certificate vauIssuerCertificate,
 51	      List<X509Certificate> certificateChain,
 52	      byte[] ocspResponseDer)
 53	      throws CertificateValidationException {
 54	
 55	    // https://gemspec.gematik.de/docs/gemSpec/gemSpec_Krypt/latest/#A_24624-01
 56	    verifyEndUserCertificate(vauInstanceCertificate, vauIssuerCertificate, certificateChain);
 57	
 58	    verifyOcspResponse(vauInstanceCertificate, ocspResponseDer);
 59	
 60	    verifyRole(vauInstanceCertificate);
 61	  }
 62	
 63	  private void verifyEndUserCertificate(
 64	      X509Certificate vauInstanceCertificate,
 65	      X509Certificate vauIssuerCertificate,
 66	      List<X509Certificate> certificateChain)
 67	      throws CertificateValidationException {
 68	    var instanceIntermediates =
 69	        Stream.concat(Stream.of(vauIssuerCertificate), certificateChain.stream()).toList();
 70	    verifyTrustChainAgainstRoot(vauInstanceCertificate, instanceIntermediates);
 71	  }
 72	
 73	  private void verifyRole(X509Certificate endUserCertificate)
 74	      throws CertificateValidationException {
 75	    try {
 76	      var asn1Admission =
 77	          new X509CertificateHolder(endUserCertificate.getEncoded())
 78	              .getExtensions()
 79	              .getExtensionParsedValue(id_isismtt_at_admission);
 80	
 81	      var admissionInstance = AdmissionSyntax.getInstance(asn1Admission);
 82	
 83	      var contents = admissionInstance.getContentsOfAdmissions();
 84	      if (contents.length != 1) {
 85	        throw new CertificateValidationException(
 86	            "expected exactly one admission content, got %d".formatted(contents.length));
 87	      }
 88	
 89	      var content = contents[0];
 90	      var profInfos = content.getProfessionInfos();
 91	      if (profInfos.length != 1) {
 92	        throw new CertificateValidationException(
 93	            "expected exactly one profession info, got %d".formatted(profInfos.length));
 94	      }
 95	
 96	      var profInfo = profInfos[0];
 97	
 98	      var oids = profInfo.getProfessionOIDs();
 99	      if (oids.length != 1) {
100	        throw new CertificateValidationException(
101	            "expected exactly one profession oid, got %d".formatted(oids.length));
102	      }
103	
104	      var oid = oids[0];
105	
106	      if (!oid.equals(OID_EPA_VAU)) {
107	        throw new CertificateValidationException(
108	            "expected OID %s, got %s".formatted(OID_EPA_VAU, oid));
109	      }
110	
111	    } catch (IOException | CertificateEncodingException e) {
112	      throw new CertificateValidationException("bad certificate", e);
113	    }
114	  }
115	
116	  private void verifyTrustChainAgainstRoot(
117	      X509Certificate endUserCertificate, List<X509Certificate> certificateChain)
118	      throws CertificateValidationException {
119	
120	    try {
121	      var intermediates = new CollectionCertStoreParameters(certificateChain);
122	
123	      var target = new X509CertSelector();
124	      target.setCertificate(endUserCertificate);
125	
126	      var params = new PKIXBuilderParameters(trustStore, target);
127	      params.addCertStore(CertStore.getInstance("Collection", intermediates));
128	
129	      // we'll check the OCSP/CRL response separately
130	      params.setRevocationEnabled(false);
131	
132	      var builder = CertPathBuilder.getInstance("PKIX", BouncyCastleProvider.PROVIDER_NAME);
133	
134	      var result = (PKIXCertPathBuilderResult) builder.build(params);
135	      log.atDebug().log(
136	          "certificate '{}' verified with trust anchor: '{}'",
137	          endUserCertificate.getSubjectX500Principal().getName(),
138	          result.getTrustAnchor().getTrustedCert().getSubjectX500Principal().getName());
139	
140	    } catch (CertPathBuilderException
141	        | NoSuchAlgorithmException
142	        | InvalidAlgorithmParameterException e) {
143	      var name = endUserCertificate.getSubjectX500Principal().getName();
144	      throw new CertificateValidationException(
145	          "failed to validate VAU server certificate, bad certificate: " + name, e);
146	    } catch (NoSuchProviderException | KeyStoreException e) {
147	      throw new VauException("unexpected crypto exception", e);
148	    }
149	  }
150	
151	  private void verifyOcspResponse(X509Certificate vauInstanceCertificate, byte[] ocspResponseDer)
152	      throws CertificateValidationException {
153	
154	    if (ocspResponseDer == null || ocspResponseDer.length == 0) {
155	      throw new CertificateValidationException("empty OCSP response");
156	    }
157	
158	    var ocspResp = toOcspResponse(ocspResponseDer);
159	    if (ocspResp.getStatus() != OCSPResp.SUCCESSFUL) {
160	      throw new CertificateValidationException(
161	          "invalid OCSP response status: %d".formatted(ocspResp.getStatus()), null);
162	    }
163	
164	    var basicOcspResp = getBasicOcspResp(ocspResp);
165	
166	    var responderX500Name = basicOcspResp.getResponderId().toASN1Primitive().getName();
167	
168	    // is the OCSP response valid?
169	    var ocspResponderCertificate =
170	        findTrustedCertificate(responderX500Name)
171	            .orElseThrow(
172	                () ->
173	                    new VauClientException(
174	                        "no OCSP responder certificate found for %s".formatted(responderX500Name)));
175	    verifyOcspResponseSignature(ocspResponderCertificate, basicOcspResp);
176	    verifyOcspResponseAge(basicOcspResp);
177	
178	    // has exactly one response?
179	    var responses = basicOcspResp.getResponses();
180	    if (responses.length != 1) {
181	      throw new CertificateValidationException(
182	          "expected 1 OCSP response, got %d".formatted(responses.length));
183	    }
184	    var response = responses[0];
185	
186	    // status for our cert good?
187	    if (response.getCertStatus() != CertificateStatus.GOOD) {
188	      throw new CertificateValidationException(
189	          "invalid OCSP response certificate status: %s".formatted(response.getCertStatus()));
190	    }
191	
192	    verifyCertHash(vauInstanceCertificate, response);
193	  }
194	
195	  Optional<X509Certificate> findTrustedCertificate(X500Name subject) {
196	    try {
197	      var enumeration = trustStore.aliases();
198	      while (enumeration.hasMoreElements()) {
199	        var alias = enumeration.nextElement();
200	        var cert = (X509Certificate) trustStore.getCertificate(alias);
201	
202	        // making sure we have the bouncycastle X500Name for both
203	        var certPrincipal =
204	            new org.bouncycastle.asn1.x500.X500Name(cert.getSubjectX500Principal().getName());
205	        if (certPrincipal.equals(subject)) {
206	          return Optional.of(cert);
207	        }
208	      }
209	      return Optional.empty();
210	    } catch (KeyStoreException e) {
211	      throw new VauClientException(
212	          "cannot find certificate for %s in truststore".formatted(subject.toString()), e);
213	    }
214	  }
215	
216	  void verifyOcspResponseAge(BasicOCSPResp ocspResponse) throws CertificateValidationException {
217	    var now = clock.instant();
218	
219	    var producedAt = ocspResponse.getProducedAt().toInstant();
220	
221	    if (Duration.between(producedAt, now).compareTo(ocspResponseAge) > 0) {
222	      throw new CertificateValidationException("OCSP response too old");
223	    }
224	  }
225	
226	  /** Verifies teh cert hash of the parameterized OCSP Response against the certificate. */
227	  private void verifyCertHash(X509Certificate endUserCertificate, SingleResp ocspResponseEntry)
228	      throws CertificateValidationException {
229	    try {
230	      var singleOcspRespAsn1 =
231	          ocspResponseEntry.getExtension(id_isismtt_at_certHash).getParsedValue();
232	      var ocspCertHashBytes = CertHash.getInstance(singleOcspRespAsn1).getCertificateHash();
233	      var eeCertHashBytes = sha256(endUserCertificate.getEncoded());
234	
235	      if (!MessageDigest.isEqual(ocspCertHashBytes, eeCertHashBytes)) {
236	        throw new CertificateValidationException(
237	            "ocsp cert hash does not match end user cert hash");
238	      }
239	    } catch (CertificateEncodingException e) {
240	      throw new CertificateValidationException("invalid end user certificate", e);
241	    }
242	  }
243	
244	  private static byte[] sha256(byte[] bytes) {
245	    try {
246	      var md = MessageDigest.getInstance("SHA-256");
247	      return md.digest(bytes);
248	    } catch (NoSuchAlgorithmException e) {
249	      throw new VauException("SHA-256 not supported", e);
250	    }
251	  }
252	
253	  protected void verifyOcspResponseSignature(
254	      X509Certificate vauIssuerCertificate, BasicOCSPResp ocspResponse)
255	      throws CertificateValidationException {
256	    try {
257	      var cvp =
258	          new JcaContentVerifierProviderBuilder()
259	              .setProvider(BouncyCastleProvider.PROVIDER_NAME)
260	              .build(vauIssuerCertificate.getPublicKey());
261	      if (!ocspResponse.isSignatureValid(cvp)) {
262	        throw new CertificateValidationException("invalid OCSP response signature");
263	      }
264	    } catch (final OCSPException | OperatorCreationException e) {
265	      throw new CertificateValidationException("error validating OCSP response", e);
266	    }
267	  }
268	
269	  public static OCSPResp toOcspResponse(byte[] ocspResponseDer)
270	      throws CertificateValidationException {
271	    try {
272	      return new OCSPResp(ocspResponseDer);
273	    } catch (IOException e) {
274	      throw new CertificateValidationException("failed to decode OCSP response", e);
275	    }
276	  }
277	
278	  public static BasicOCSPResp getBasicOcspResp(OCSPResp ocspResponse)
279	      throws CertificateValidationException {
280	    try {
281	      return (BasicOCSPResp) ocspResponse.getResponseObject();
282	    } catch (OCSPException e) {
283	      throw new CertificateValidationException("failed to decode OCSP response", e);
284	    }
285	  }
286	}
