 23	public class VauCertificateClient {
 24	
 25	  private static final Logger log = LoggerFactory.getLogger(VauCertificateClient.class);
 26	
 27	  private final TrustValidator trustValidator;
 28	  private final CBORMapper mapper = new CBORMapper();
 29	  private final HttpClient outerHttpClient;
 30	
 31	  public VauCertificateClient(HttpClient outerHttpClient, TrustValidator trustValidator) {
 32	    this.trustValidator = trustValidator;
 33	    this.outerHttpClient = outerHttpClient;
 34	  }
 35	
 36	  public CertData fetchAndValidate(URI endpoint, byte[] certHash, int cdv, byte[] ocspResponseDer)
 37	      throws CertificateValidationException {
 38	
 39	    if (log.isDebugEnabled()) {
 40	      log.atDebug().log("ocsp response:\n{}", Hex.toHexString(ocspResponseDer));
 41	    }
 42	
 43	    var data = fetch(endpoint, certHash, cdv);
 44	
 45	    var ca = parseDerCertificate(data.ca());
 46	    var cert = parseDerCertificate(data.cert());
 47	    var chain = data.rcaChain().stream().map(VauCertificateClient::parseDerCertificate).toList();
 48	
 49	    trustValidator.validate(cert, ca, chain, ocspResponseDer);
 50	    return new CertData(cert, ca, chain);
 51	  }
 52	
 53	  private String certificateDerChainToPem(List<byte[]> certificates) {
 54	    return certificates.stream().map(this::certificateDerToPem).collect(Collectors.joining());
 55	  }
 56	
 57	  private String certificateDerToPem(byte[] certificate) {
 58	
 59	    try (var sw = new StringWriter()) {
 60	      try (var w = new PemWriter(sw)) {
 61	        var pemObject = new PemObject("CERTIFICATE", certificate);
 62	        w.writeObject(pemObject);
 63	        w.flush();
 64	      }
 65	      return sw.toString();
 66	    } catch (IOException e) {
 67	      throw new IllegalStateException("What the heck? Should not happen.", e);
 68	    }
 69	  }
 70	
 71	  public CertDataResponse fetch(URI endpoint, byte[] certHash, int cdv) {
 72	    var hex = HexFormat.of();
 73	    var certIdentifier = "%s-%d".formatted(hex.formatHex(certHash), cdv);
 74	    var certEndpoint = endpoint.resolve("/CertData.%s".formatted(certIdentifier));
 75	    var res = outerHttpClient.call(new HttpRequest(certEndpoint, "GET", List.of(), null));
 76	    if (res.status() != 200) {
 77	      throw new VauClientException(
 78	          "invalid code %d, expected 200: GET %s".formatted(res.status(), certEndpoint));
 79	    }
 80	    try {
 81	      var data = mapper.readValue(res.body(), CertDataResponse.class);
 82	
 83	      if (log.isDebugEnabled()) {
 84	        log.atDebug().log("cert response:\n{}", certificateDerToPem(data.cert()));
 85	        log.atDebug().log("ca response:\n{}", certificateDerToPem(data.ca()));
 86	        log.atDebug().log("chain response:\n{}", certificateDerChainToPem(data.rcaChain()));
 87	      }
 88	
 89	      return data;
 90	    } catch (IOException e) {
 91	      throw new VauClientException("invalid response body: GET %s".formatted(certEndpoint), e);
 92	    }
 93	  }
 94	
 95	  private static X509Certificate parseDerCertificate(byte[] certBytes) {
 96	    try (var certInputStream = new ByteArrayInputStream(certBytes)) {
 97	      // MUST be bouncycastle to deal with the brainpool certificates
 98	      var certFactory = CertificateFactory.getInstance("X.509", BouncyCastleProvider.PROVIDER_NAME);
 99	      var cert = certFactory.generateCertificate(certInputStream);
100	      if (cert instanceof X509Certificate x509Cert) {
101	        return x509Cert;
102	      }
103	      throw new VauProtocolException(
104	          "VAU channel certificate is not an X.509 certificate, got: %s".formatted(cert.getType()));
105	    } catch (IOException | CertificateException | NoSuchProviderException e) {
106	      throw new VauProtocolException("failed to parse VAU channel certificate", e);
107	    }
108	  }
109	}

