16	public class SignedPublicKeysTrustValidatorImpl implements SignedPublicKeysTrustValidator {
17	
18	  private static final Logger log =
19	      LoggerFactory.getLogger(SignedPublicKeysTrustValidatorImpl.class);
20	  private final VauCertificateClient certDataClient;
21	  private final URI vauUri;
22	
23	  public SignedPublicKeysTrustValidatorImpl(
24	      HttpClient outerClient, TrustValidator trustValidator, URI vauUri) {
25	    this.vauUri = vauUri;
26	    certDataClient = new VauCertificateClient(outerClient, trustValidator);
27	  }
28	
29	  @Override
30	  public boolean isTrusted(SignedPublicKeys signedPublicKeys) {
31	    try {
32	      var certs =
33	          certDataClient.fetchAndValidate(
34	              vauUri,
35	              signedPublicKeys.certHash(),
36	              signedPublicKeys.cdv(),
37	              signedPublicKeys.ocspResponse());
38	
39	      var ecdsa = Signature.getInstance("SHA256withECDSA", BouncyCastleProvider.PROVIDER_NAME);
40	      ecdsa.initVerify(certs.cert());
41	      ecdsa.update(signedPublicKeys.signedPubKeys());
42	
43	      // https://www.rfc-editor.org/rfc/rfc7515.html#appendix-A.3.1
44	      var signatureDer = ECDSA.transcodeSignatureToDER(signedPublicKeys.signatureEs256());
45	      ecdsa.verify(signatureDer);
46	
47	    } catch (CertificateValidationException
48	        | InvalidKeyException
49	        | SignatureException
50	        | NoSuchAlgorithmException
51	        | JOSEException
52	        | NoSuchProviderException e) {
53	      log.atDebug().setCause(e).log("failed to validate certificate: {}", e.getMessage());
54	      return false;
55	    }
56	    return true;
57	  }
58	}

